from dataclasses import dataclass, field
from typing import Literal

@dataclass
class SponsorOKR:
    objective: str
    key_result: str
    target: float
    actual: float
    unit: str = "%"

    @property
    def rag(self) -> Literal["Green", "Amber", "Red"]:
        ratio = self.actual / self.target if self.target else 0
        if ratio >= 0.9:
            return "Green"
        if ratio >= 0.7:
            return "Amber"
        return "Red"

@dataclass
class SponsorScorecard:
    sponsor_name: str
    programme: str
    quarter: str
    okrs: list[SponsorOKR] = field(default_factory=list)
    commitments_met: int = 0
    commitments_total: int = 0

    @property
    def commitment_rate(self) -> float:
        if not self.commitments_total:
            return 0.0
        return self.commitments_met / self.commitments_total * 100

    def overall_rag(self) -> Literal["Green", "Amber", "Red"]:
        reds = sum(1 for o in self.okrs if o.rag == "Red")
        ambers = sum(1 for o in self.okrs if o.rag == "Amber")
        if reds >= 1 or self.commitment_rate < 70:
            return "Red"
        if ambers >= 2 or self.commitment_rate < 90:
            return "Amber"
        return "Green"

    def summary(self) -> str:
        lines = [
            f"Sponsor Scorecard — {self.sponsor_name} | {self.programme} | {self.quarter}",
            f"  Commitment rate: {self.commitment_rate:.0f}%",
            f"  Overall RAG: {self.overall_rag()}",
        ]
        for okr in self.okrs:
            lines.append(
                f"  [{okr.rag:5s}] {okr.key_result}: {okr.actual}/{okr.target}{okr.unit}"
            )
        return "\n".join(lines)

# Example usage
sc = SponsorScorecard(
    sponsor_name="Jane Doe (CTO)",
    programme="Customer-Facing GenAI",
    quarter="Q2-2026",
    commitments_met=8,
    commitments_total=10,
    okrs=[
        SponsorOKR("Accelerate revenue", "Cases deflected by AI assistant", 40, 38),
        SponsorOKR("Reduce cost", "Agent cost per query vs baseline", 30, 22),
        SponsorOKR("Ensure compliance", "Bias audit pass rate", 100, 94),
    ],
)
print(sc.summary())
# Sponsor Scorecard — Jane Doe (CTO) | Customer-Facing GenAI | Q2-2026
#   Commitment rate: 80%
#   Overall RAG: Amber
#   [Green] Cases deflected by AI assistant: 38/40%
#   [Amber] Agent cost per query vs baseline: 22/30%
#   [Amber] Bias audit pass rate: 94/100%
